components.OutflowTimeline:
export default function OutflowTimeline({ scheduled, recurring, scheduledRaw, recurringRaw }) {
  const payments = Array.isArray(scheduled) ? scheduled : (scheduledRaw?.data ?? []);
  const subs = Array.isArray(recurring) ? recurring : (recurringRaw?.subscriptions ?? []);

  const items = [];

  (payments || []).forEach(p => {
    const dateStr = p.nextDate || p.date || p.scheduledDate || p.dueDate || p.paymentDate;
    const amountCents = p.amountCents ?? p.amount ?? 0;
    items.push({
      id: p.id || p.paymentId || Math.random(),
      label: p.payee || p.name || p.description || p.merchant || 'Payment',
      dateStr,
      amountCents,
      type: 'scheduled',
    });
  });

  (subs || []).forEach(s => {
    const dateStr = s.nextDate || s.nextBillingDate || s.renewalDate || s.date;
    const amountCents = s.amountCents ?? s.amount ?? 0;
    items.push({
      id: s.id || s.subscriptionId || Math.random(),
      label: s.merchant || s.name || s.description || 'Subscription',
      dateStr,
      amountCents,
      type: 'subscription',
    });
  });

  items.sort((a, b) => {
    if (!a.dateStr && !b.dateStr) return 0;
    if (!a.dateStr) return 1;
    if (!b.dateStr) return -1;
    return new Date(a.dateStr).getTime() - new Date(b.dateStr).getTime();
  });

  const totalCents = items.reduce((sum, i) => sum + (i.amountCents || 0), 0);

  if (items.length === 0) {
    return (
      <Surface>
        <Stack gap={2}>
          <Text variant="caption" text="No upcoming payments or renewals found." />
        </Stack>
      </Surface>
    );
  }

  function formatDate(dateStr) {
    if (!dateStr) return '—';
    const d = new Date(dateStr);
    if (isNaN(d.getTime())) return dateStr;
    const now = new Date('2026-07-21');
    const diffDays = Math.round((d.getTime() - now.getTime()) / (1000 * 60 * 60 * 24));
    const label = d.toLocaleDateString('en-US', { month: 'short', day: 'numeric' });
    if (diffDays === 0) return `Today · ${label}`;
    if (diffDays === 1) return `Tomorrow · ${label}`;
    if (diffDays > 0 && diffDays <= 6) return `In ${diffDays} days · ${label}`;
    return label;
  }

  return (
    <Stack gap={3}>
      <Surface>
        <Row gap={4} style={{ justifyContent: 'space-between', alignItems: 'center' }}>
          <Stack gap={1}>
            <Text variant="caption" text="Total going out" />
            <span style={{ fontSize: '2rem', fontWeight: 700, fontFamily: 'var(--vendo-heading-family)', color: 'var(--vendo-color-text)', letterSpacing: '-0.02em' }}>
              {fmt.money(totalCents)}
            </span>
          </Stack>
          <Stack gap={1} style={{ textAlign: 'right' }}>
            <Text variant="caption" text="Upcoming items" />
            <span style={{ fontSize: '1.5rem', fontWeight: 600, color: 'var(--vendo-color-text)' }}>{items.length}</span>
          </Stack>
        </Row>
      </Surface>

      <Surface>
        <Stack gap={0}>
          {items.map((item, idx) => (
            <div key={item.id} style={{
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'space-between',
              padding: '14px 0',
              borderBottom: idx < items.length - 1 ? '1px solid var(--vendo-color-border)' : 'none',
            }}>
              <Row gap={3} style={{ alignItems: 'center' }}>
                <div style={{
                  width: 36,
                  height: 36,
                  borderRadius: 'var(--vendo-radius-medium)',
                  background: 'var(--vendo-color-background)',
                  border: '1px solid var(--vendo-color-border)',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: '1rem',
                  flexShrink: 0,
                }}>
                  {item.type === 'subscription' ? '🔄' : '📅'}
                </div>
                <Stack gap={0}>
                  <span style={{ fontWeight: 500, color: 'var(--vendo-color-text)', fontSize: 'var(--vendo-font-size)' }}>{item.label}</span>
                  <span style={{ fontSize: '0.8rem', color: 'var(--vendo-color-muted)' }}>{formatDate(item.dateStr)}</span>
                </Stack>
              </Row>
              <Stack gap={0} style={{ textAlign: 'right', flexShrink: 0 }}>
                <span style={{ fontWeight: 600, color: 'var(--vendo-color-text)', fontSize: 'var(--vendo-font-size)' }}>
                  {item.amountCents ? `−${fmt.money(item.amountCents)}` : '—'}
                </span>
                <span style={{ fontSize: '0.75rem', color: 'var(--vendo-color-muted)', textTransform: 'capitalize' }}>{item.type}</span>
              </Stack>
            </div>
          ))}
        </Stack>
      </Surface>
    </Stack>
  );
}
